import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/linux-java-version.Bae4eMgj.js";const a=JSON.parse(`{"title":"Instalando Java no Linux","description":"Um guia passo a passo de como instalar Java no Linux.","frontmatter":{"title":"Instalando Java no Linux","description":"Um guia passo a passo de como instalar Java no Linux.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"pt_br/1.21.1/players/installing-java/linux.md","filePath":"versions/1.21.1/translated/pt_br/players/installing-java/linux.md","lastUpdated":1761424914000}`);var o={name:`pt_br/1.21.1/players/installing-java/linux.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalando Java no Linux <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalando Java no Linux”">​</a></h1><p>Este guia o orientará na instalação do Java 17 no Linux.</p><h2 id="_1-verificar-se-o-java-ja-esta-instalado" tabindex="-1">1. Verificar Se o Java Já Está Instalado <a class="header-anchor" href="#_1-verificar-se-o-java-ja-esta-instalado" aria-label="Permalink to “1. Verificar Se o Java Já Está Instalado”">​</a></h2><p>Abra um terminal, digite <code>java -version</code>, e pressione <kbd>Enter</kbd>.</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="Terminal com &quot;java -version&quot; digitado" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Para usar a maioria das versões modernas do Minecraft, você precisará ter pelo menos o Java 17 instalado. Se este comando exibir uma versão inferior a 17, será necessário atualizar sua instalação do Java atual.</p></div><h2 id="_2-baixando-e-instalando-java-17" tabindex="-1">2. Baixando e instalando Java 17 <a class="header-anchor" href="#_2-baixando-e-instalando-java-17" aria-label="Permalink to “2. Baixando e instalando Java 17”">​</a></h2><p>Recomendamos usar o OpenJDK 17, que está disponível para a maioria das distribuições Linux.</p><h3 id="arch-linux" tabindex="-1">Arch Linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to “Arch Linux”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Para mais informações na instalação do Java no Arch Linux, veja a <a href="https://wiki.archlinux.org/title/Java_(Portugu%C3%AAs)" target="_blank" rel="noreferrer">Wiki do Arch Linux</a>.</p></div><p>Você pode instalar a JRE mais recente através de repositórios oficiais:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Se estiver rodando um servidor sem a necessidade de uma interface gráfica, você pode instalar a versão headless:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Se você planeja desenvolver mods, precisará do JDK:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jdk-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="debian-ubuntu" tabindex="-1">Debian/Ubuntu <a class="header-anchor" href="#debian-ubuntu" aria-label="Permalink to “Debian/Ubuntu”">​</a></h3><p>Você pode instalar o Java 17 usando <code>apt</code> com os seguintes comandos:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openjdk-17-jdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="fedora" tabindex="-1">Fedora <a class="header-anchor" href="#fedora" aria-label="Permalink to “Fedora”">​</a></h3><p>Você pode instalar o Java 17 usando <code>dnf</code> com os seguintes comandos:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Se você não precisa de uma interface gráfica, você pode instalar a versão headless:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Se você planeja desenvolver mods, precisará do JDK:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk-devel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="outras-distribuicoes-linux" tabindex="-1">Outras distribuições Linux <a class="header-anchor" href="#outras-distribuicoes-linux" aria-label="Permalink to “Outras distribuições Linux”">​</a></h3><p>Se sua distribuição não foi listada acima, você pode baixar a JRE mais recente pelo <a href="https://adoptium.net/temurin/" target="_blank" rel="noreferrer">Adoptium</a></p><p>Você deve consultar um guia próprio de sua distribuição se planeja desenvolver mods.</p><h2 id="_3-verificar-se-o-java-17-esta-instalado" tabindex="-1">3. Verificar se o Java 17 está instalado <a class="header-anchor" href="#_3-verificar-se-o-java-17-esta-instalado" aria-label="Permalink to “3. Verificar se o Java 17 está instalado”">​</a></h2><p>Assim que a instalação terminar, você pode verificar se o Java 17 está instalado abrindo o terminal novamente e digitando <code>java -version</code>.</p><p>Se o comando for executado com êxito, você verá algo como mostrado anteriormente onde a versão do Java é exibida:</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="Terminal com &quot;java -version&quot; digitado" loading="lazy"></p>`,33)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};